VALUES
  ('elementary-6f0ba476-moex-00894', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依現行所得稅法規定，下列何者正確？', '["綜合所得稅課稅級距之金額每遇消費者物價指數較上次調整年度之指數上漲累計達 10%以上時，按上 漲程度調整之", "綜合所得稅課稅級距共分6級，最高稅率為45%", "綜合所得稅課稅級距共分5級，最低稅率為6%", "營利事業全年課稅所得額超過12萬元未逾50萬元者，109年度營利事業所得稅稅率為20%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00895', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '營利事業遇有解散、廢止、合併或轉讓情事時，應於截至解散、廢止、合併或轉讓之日止，辦理當期決 算，於多久期限內，依規定格式，向該管稽徵機關申報其營利事業所得額及應納稅額，並於提出申報前 自行繳納之？', '["15日", "30日", "45日", "3個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00896', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '下列有關我國所得稅法所稱中華民國境內居住之個人之敘述何者錯誤？', '["在中華民國境內有住所，並經常居住中華民國境內者", "個人於一課稅年度內在中華民國境內設有戶籍，且於一課稅年度內在中華民國境內居住合計滿31天", "在中華民國境內無住所，而於一課稅年度內在中華民國境內居留合計滿183天者", "中華民國境內居住之個人應辦理就源扣繳完稅"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00897', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，下列那些稅捐之徵收優先於一切債權及抵押權？', '["所得稅、行政執行處執行拍賣或變賣貨物應課徵之營業稅", "貨物稅、地價稅", "房屋稅、土地增值稅", "土地增值稅、遺產及贈與稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00898', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依據我國現行所得稅法之規定，下列有關免稅所得之敘述何者錯誤？', '["個人取自營利事業贈與之財產已納贈與稅，所以免課所得稅", "傷害或死亡之損害賠償金，及依國家賠償法規定取得之賠償金免稅", "公、教、軍、警人員及勞工所領政府發給之實物配給或其代金及房租津貼免稅", "個人出售家庭日常使用之衣物、家具免稅"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00899', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '甲公司為總機構在中華民國境內之公司，其於民國109年8月出售房地一筆，售價5,000萬元，該房地為 民國108年12月取得，取得成本為4,800萬元，持有期間未滿1年，土地漲價總數額300萬元，繳納土 地增值稅60萬元。試問下列有關該筆房地交易之敘述何者錯誤？', '["甲公司出售該房地之交易所得為200萬元", "甲公司出售該房地應計入營利事業所得額之數額為0", "甲公司出售持有未滿1年之房地應以45%稅率分離課稅", "甲公司出售該房地之土地增值稅60萬元不得列為費用扣除"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00900', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '王先生於民國109年度在國內有薪資收入100萬元、稿費收入10萬元、取自銀行利息收入20萬元，試 問王先生民國109年度應申報之綜合所得總額為多少元？', '["80萬元", "100萬元", "120萬元", "130萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00901', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '除依規定不計入贈與總額之贈與外，贈與人在 1 年內贈與他人之財產總值超過贈與稅免稅額時，應於超 過免稅額之贈與行為發生後多久時間內，向主管稽徵機關辦理贈與稅申報？', '["15日", "30日", "2個月", "6個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00902', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依遺產及贈與稅法規定，遺產稅之納稅義務人依序為：', '["依法選定遺產管理人、遺囑執行人、繼承人及受遺贈人", "繼承人及受遺贈人、遺囑執行人、依法選定遺產管理人", "遺囑執行人、依法選定遺產管理人、繼承人及受遺贈人", "遺囑執行人、繼承人及受遺贈人、依法選定遺產管理人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00903', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '下列有關我國遺產及贈與稅法之規定何者錯誤？', '["被繼承人如為經常居住中華民國境外之中華民國國民，或非中華民國國民，不能減除遺產稅免稅額1,200 萬元", "遺產稅或贈與稅應納稅額在30萬元以上，納稅義務人確有困難，不能一次繳納現金時，得於納稅期限 內，向該管稽徵機關申請，分18期以內繳納，每期間隔以不超過2個月為限", "遺產稅或贈與稅應納稅額在30萬元以上，納稅義務人確有困難，不能一次繳納現金時，得於納稅期限 內，就現金不足繳納部分申請以在中華民國境內之課徵標的物或納稅義務人所有易於變價及保管之實 物一次抵繳", "扶養義務人為受扶養人支付之生活費、教育費及醫藥費不計入贈與總額"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "b551c80272d7", "answer_pdf_sha1": "f8c75d40d6c9", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
